// Parse RSS XML and extract article links + titles
const xml = $input.first().json.data || '';
const feedMeta = $('Define All RSS Sources').first().json;

// Extract items from RSS XML using regex
const items = [];
const itemMatches = xml.match(/<item[^>]*>[\s\S]*?<\/item>/gi) || [];

// Cut-off: only articles from last 2 hours
const cutoff = Date.now() - (2 * 60 * 60 * 1000);

for (const item of itemMatches.slice(0, 15)) { // max 15 per feed
  const titleMatch  = item.match(/<title>(?:<!\[CDATA\[)?([^\]<]+?)(?:\]\]>)?<\/title>/i);
  const linkMatch   = item.match(/<link>([^<]+)<\/link>/i) ||
                      item.match(/<link[^>]+href="([^"]+)"/i);
  const dateMatch   = item.match(/<pubDate>([^<]+)<\/pubDate>/i) ||
                      item.match(/<published>([^<]+)<\/published>/i) ||
                      item.match(/<updated>([^<]+)<\/updated>/i);

  const link  = linkMatch?.[1]?.trim();
  const title = titleMatch?.[1]?.trim() || 'Untitled';
  const dateStr = dateMatch?.[1]?.trim();
  const pubTime = dateStr ? new Date(dateStr).getTime() : Date.now();

  // Skip if older than 2 hours (unless feed_level is set, then always include to build initial DB)
  // Allow all for first 30 days to build knowledge base
  if (!link || !link.startsWith('http')) continue;

  // Skip non-article links (tag pages, author pages)
  if (!link.includes('medium.com/') && !link.includes('reddit.com/r/') &&
      !link.includes('portswigger.net/') && !link.includes('google.com/')) continue;

  items.push({
    json: {
      link: link,
      title: title,
      pub_date: dateStr || new Date().toISOString(),
      feed_level: feedMeta.level,
      feed_label: feedMeta.label,
      feed_url: feedMeta.url
    }
  });
}

console.log(`Feed: ${feedMeta.label} → ${items.length} articles`);
return items;

// Check if article URL already exists in dashboard
const https = require('https');
const http = require('http');
const item = $input.first().json;

const exists = await new Promise((resolve) => {
  const url = `http://localhost:3000/api/check-url?url=${encodeURIComponent(item.link)}`;
  http.get(url, (res) => {
    let data = '';
    res.on('data', d => data += d);
    res.on('end', () => {
      try { resolve(JSON.parse(data).exists); }
      catch(e) { resolve(false); }
    });
  }).on('error', () => resolve(false));
});

if (exists) {
  console.log('SKIP (already saved):', item.title?.substring(0, 50));
  return [];
}

return [{ json: item }];

const html = $input.first().json.data || '';
const meta = $('Dedup — Skip Already Saved').first().json;

// Strip HTML tags and clean text
const text = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ')
  .replace(/\s{2,}/g, ' ').trim();

// Require at least 400 chars — less = paywalled or failed
if (text.length < 400) {
  console.log('SKIP (too short / paywalled):', meta.title?.substring(0, 50));
  return [];
}

return [{ json: {
  ...meta,
  article_text: text.substring(0, 14000)
} }];

