try {
  const raw = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const gemini = JSON.parse(cleaned);

  if (gemini.skip || !gemini.score || gemini.score < 6) {
    const meta = $('Extract & Validate Article Text').first().json;
    console.log(`TRASH (score ${gemini.score}): ${meta.title?.substring(0,50)}`);
    return [];
  }

  const articleData = $('Extract & Validate Article Text').first().json;

  // Use feed_level as fallback for vapt_level if Gemini doesn't determine one
  const vapt_level = gemini.vapt_level || articleData.feed_level || 'Medium';

  return [{ json: {
    ...articleData,
    quality_score:   gemini.score,
    vapt_level:      vapt_level,
    category:        gemini.category || 'Web Fundamentals',
    vulnerability_type: gemini.vulnerability_type || 'Other',
    severity:        gemini.severity || 'Medium',
    tools_mentioned: gemini.tools_mentioned || [],
    one_line_summary: gemini.one_line_summary || '',
    beginner_context: gemini.beginner_context || ''
  } }];
} catch(e) {
  console.log('Gemini parse error:', e.message);
  return [];
}

const fs = require('fs');
const path = require('path');
const d = $input.first().json;

const vault = process.env.OBSIDIAN_VAULT || '/home/pavan/SecurityKB';
const folder = path.join(vault, d.obsidian_folder || 'Misc');
fs.mkdirSync(folder, { recursive: true });

const filepath = path.join(folder, `${d.obsidian_filename}.md`);
fs.writeFileSync(filepath, d.obsidian_content, 'utf8');

console.log(`[Obsidian] Written: ${filepath}`);
return [{ json: { saved: true, path: filepath } }];
